bool Assets::InitializePartition()
{
    // Find the assets partition
    const esp_partition_t *partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA, 
        ESP_PARTITION_SUBTYPE_DATA_SPIFFS, 
        "assets");

    if (partition == nullptr)
    {
        ESP_LOGE(TAG, "Failed to find assets partition");
        return false;
    }

    partition_ = partition;

    // Map the partition into memory
    esp_err_t err = esp_partition_mmap(partition, 0, partition->size, 
                                       ESP_PARTITION_MMAP_DATA, 
                                       (const void**)&mmap_root_, 
                                       &mmap_handle_);

    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        return false;
    }

    // Check if the partition has valid data (magic number)
    if (mmap_root_[0] != 'A' || mmap_root_[1] != 'S' || 
        mmap_root_[2] != 'S' || mmap_root_[3] != 'E')
    {
        ESP_LOGE(TAG, "Assets partition has invalid magic number");
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        return false;
    }

    // Calculate and verify checksum
    uint32_t stored_checksum = *(uint32_t*)(mmap_root_ + 4);
    uint32_t calculated_checksum = CalculateChecksum(mmap_root_ + 8, partition->size - 8);

    if (stored_checksum != calculated_checksum)
    {
        ESP_LOGE(TAG, "Assets partition checksum mismatch: expected 0x%04X, got 0x%04X", 
                 calculated_checksum, stored_checksum);
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        return false;
    }

    checksum_valid_ = true;

    // Parse the asset table and build index
    assets_.clear();

    // Skip the header (8 bytes for magic + checksum)
    const char* data_ptr = mmap_root_ + 8;
    uint32_t offset = 8;

    // Parse each asset entry
    while (offset < partition->size)
    {
        const mmap_assets_table* asset_table = (const mmap_assets_table*)data_ptr;

        // Check if we have enough data for a complete entry
        if (offset + sizeof(mmap_assets_table) > partition->size)
        {
            ESP_LOGW(TAG, "Incomplete asset entry at offset %u", offset);
            break;
        }

        // Check if this is a valid asset entry (non-zero size)
        if (asset_table->asset_size == 0)
        {
            break; // End of valid entries
        }

        // Add to our asset index
        AssetInfo info;
        info.size = asset_table->asset_size;
        info.offset = asset_table->asset_offset;
        info.width = asset_table->asset_width;
        info.height = asset_table->asset_height;

        // Copy asset name (ensure null termination)
        strncpy(info.name, asset_table->asset_name, sizeof(info.name) - 1);
        info.name[sizeof(info.name) - 1] = '\0';

        assets_[info.name] = info;

        // Move to next entry
        offset += sizeof(mmap_assets_table);
        data_ptr += sizeof(mmap_assets_table);
    }

    ESP_LOGI(TAG, "Successfully initialized assets partition with %zu assets", assets_.size());
    return true;
}

