bool Assets::Apply()
{
    if (!partition_valid_ || !checksum_valid_)
    {
        ESP_LOGE(TAG, "Assets partition is not valid");
        return false;
    }

    // Load index.json from assets
    void* json_data = nullptr;
    size_t json_size = 0;

    if (!GetAssetData("index.json", json_data, json_size))
    {
        ESP_LOGE(TAG, "Failed to load index.json");
        return false;
    }

    // Parse JSON configuration
    cJSON* root = cJSON_Parse(static_cast<const char*>(json_data));
    if (root == nullptr)
    {
        ESP_LOGE(TAG, "Failed to parse index.json");
        return false;
    }

    // Validate asset version
    cJSON* version = cJSON_GetObjectItem(root, "version");
    if (version == nullptr || !cJSON_IsString(version))
    {
        ESP_LOGE(TAG, "Invalid or missing version in index.json");
        cJSON_Delete(root);
        return false;
    }

    // Check if this is a supported version
    const char* asset_version = version->valuestring;
    ESP_LOGI(TAG, "Applying assets version: %s", asset_version);

    // Process UI theme if present
    cJSON* theme = cJSON_GetObjectItem(root, "theme");
    if (theme != nullptr && cJSON_IsObject(theme))
    {
        // Load theme configuration
        cJSON* theme_name = cJSON_GetObjectItem(theme, "name");
        if (theme_name != nullptr && cJSON_IsString(theme_name))
