bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    if (!partition_valid_) {
        ESP_LOGE(TAG, "Assets partition is not valid");
        return false;
    }

    // Create HTTP client
    esp_http_client_config_t config = {
        .url = url.c_str(),
        .event_handler = NULL,
        .timeout_ms = 30000,
    };

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (client == NULL) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    // Get content length first
    esp_err_t err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Get content length
    size_t content_length = esp_http_client_get_content_length(client);
    if (content_length == -1) {
        ESP_LOGE(TAG, "Failed to get content length");
        esp_http_client_cleanup(client);
        return false;
    }

    // Check if we have enough space
    if (content_length > partition_->size - 12) {
        ESP_LOGE(TAG, "Content size %zu exceeds partition size %zu", content_length, partition_->size);
        esp_http_client_cleanup(client);
        return false;
    }

    // Erase the entire partition
    ESP_LOGI(TAG, "Erasing partition...");
    err = esp_partition_erase_range(partition_, 0, partition_->size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase partition: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Prepare to write data
    uint8_t *buffer = new uint8_t[4096];
    if (buffer == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate buffer");
        esp_http_client_cleanup(client);
        return false;
    }

    size_t total_written = 0;
    size_t last_update_time = 0;
    size_t last_bytes_written = 0;
    size_t current_speed = 0;
    int last_progress = -1;

    ESP_LOGI(TAG, "Starting download of %zu bytes", content_length);

    // Start downloading
    while (total_written < content_length) {
        size_t remaining = content_length - total_written;
        size_t to_read = (remaining > 4096) ? 4096 : remaining;

        int bytes_read = esp_http_client_read(client, reinterpret_cast<char*>(buffer), to_read);
        if (bytes_read <= 0) {
            if (bytes_read == 0) {
                // End of stream
                break;
            } else {
                ESP_LOGE(TAG, "Failed to read from HTTP client: %d", bytes_read);
                delete[] buffer;
                esp_http_client_cleanup(client);
                return false;
            }
        }

        // Write to flash
        err = esp_partition_write(partition_, 12 + total_written, buffer, bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to partition: %s", esp_err_to_name(err));
            delete[] buffer;
            esp_http_client_cleanup(client);
            return false;
        }

        total_written += bytes_read;

        // Update progress
        int progress = (total_written * 100) / content_length;
        if (progress != last_progress) {
            last_progress = progress;

            // Calculate speed every 100ms
            uint64_t now = esp_timer_get_time();
            if (now - last_update_time >= 100000) { // 100ms
                current_speed = (total_written - last_bytes_written) * 10; // Bytes per second
                last_bytes_written = total_written;
                last_update_time = now;

                if (progress_callback) {
                    progress_callback(progress, current_speed);
                }
            } else if (progress_callback && (progress % 10 == 0)) {
                // Periodic callback for progress updates
                progress_callback(progress, current_speed);
            }
        }
    }

    // Write header information
    uint32_t file_count = 0;
    uint32_t checksum = CalculateChecksum(reinterpret_cast<const char*>(mmap_root_ + 12), total_written);

    // Write header (file count, checksum, data length)
    uint8_t header[12];
    memcpy(header, &file_count, 4);  // file count
    memcpy(header + 4, &checksum, 4);  // checksum
    memcpy(header + 8, &total_written, 4);  // data length

    err = esp_partition_write(partition_, 0, header, 12);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to write header: %s", esp_err_to_name(err));
        delete[] buffer;
        esp_http_client_cleanup(client);
        return false;
    }

    // Clean up
    delete[] buffer;
    esp_http_client_cleanup(client);

    ESP_LOGI(TAG, "Download completed successfully");

    // Re-initialize partition to reflect changes
    return InitializePartition();
}

