    esp_err_t err = esp_efuse_read_field_blob(ESP_EFUSE_MAC_FACTORY, efuse_mac, 48);

    if (err == ESP_OK) {
        // Convert MAC address to string format (using first 6 bytes)
        char mac_str[13]; // 12 hex chars + null terminator
        snprintf(mac_str, sizeof(mac_str), "%02X%02X%02X%02X%02X%02X",
