        // Fallback to reading from a specific eFuse field if available
        // This approach reads a custom serial number field if it exists
        uint32_t serial_data[2] = {0};
        err = esp_efuse_read_field_blob(ESP_EFUSE_CUSTOM_SERIAL_NUMBER, (uint8_t*)serial_data, 64);

        if (err == ESP_OK) {
            // Try to convert to readable string format
            char serial_str[17]; // 16 hex chars + null terminator
            snprintf(serial_str, sizeof(serial_str), "%08X%08X", serial_data[0], serial_data[1]);

            // Only set if we have meaningful data
            if (strcmp(serial_str, "0000000000000000") != 0) {
                serial_number_ = std::string(serial_str);
                has_serial_number_ = true;

                ESP_LOGI(TAG, "Serial number initialized from custom eFuse: %s", serial_number_.c_str());
            }
        }
    }

    // If we still don't have a serial number, try another common approach
    if (!has_serial_number_) {
        // Try to read MAC address from efuse directly
        err = esp_efuse_read_field_blob(ESP_EFUSE_MAC_ADDRESS, efuse_mac, 48);

        if (err == ESP_OK) {
            char mac_str[13];
            snprintf(mac_str, sizeof(mac_str), "%02X%02X%02X%02X%02X%02X",
