                     efuse_mac[3], efuse_mac[4], efuse_mac[5]);

            // Only set if not empty
            if (strlen(mac_str) > 0) {
                serial_number_ = std::string(mac_str);
                has_serial_number_ = true;

                ESP_LOGI(TAG, "Serial number initialized from MAC eFuse: %s", serial_number_.c_str());
            }
        }
    }

    // If no serial number was found, log warning but continue
