esp_err_t Ota::CheckVersion()
{
    ESP_LOGI(TAG, "Checking for firmware updates");

    std::string url = GetCheckVersionUrl();
    if (url.empty())
    {
        ESP_LOGE(TAG, "OTA URL is empty");
        return ESP_FAIL;
    }

    auto http = SetupHttp();

    // Add activation challenge for version check if needed
    if (has_serial_number_)
    {
        // Generate a random challenge for activation
        std::string challenge;
        challenge.resize(16);
        for (int i = 0; i < 16; i++)
        {
            challenge[i] = 'A' + (rand() % 26);
        }
        activation_challenge_ = challenge;
        has_activation_challenge_ = true;
    }

    // Set up the request with proper headers
    http->SetHeader("Accept", "application/json");

    // Send GET request to check version
    if (!http->Open("GET", url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection for version check");
        return ESP_FAIL;
    }

    auto status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "Failed to check version, status code: %d", status_code);
        return ESP_FAIL;
    }

    // Read the response body
    std::string response = http->ReadAll();
    if (response.empty())
    {
        ESP_LOGE(TAG, "Empty response from version check");
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Version check response: %s", response.c_str());

    // Parse JSON response
    cJSON *json = cJSON_Parse(response.c_str());
    if (json == NULL)
    {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Check for firmware version information
    cJSON *version = cJSON_GetObjectItem(json, "version");
    if (version && cJSON_IsString(version))
    {
        std::string new_version = cJSON_GetStringValue(version);

        // Get current version
        auto current_version = esp_app_get_description()->version;
        ESP_LOGI(TAG, "Current version: %s, Available version: %s", current_version, new_version.c_str());

        // Compare versions
        if (IsNewVersionAvailable(current_version, new_version))
        {
            ESP_LOGI(TAG, "New version available: %s", new_version.c_str());

            // Check for firmware URL
            cJSON *firmware_url = cJSON_GetObjectItem(json, "firmware_url");
            if (firmware_url && cJSON_IsString(firmware_url))
            {
                firmware_url_ = cJSON_GetStringValue(firmware_url);
                ESP_LOGI(TAG, "Firmware URL: %s", firmware_url_.c_str());

                // Check for activation data
                cJSON *activation_data = cJSON_GetObjectItem(json, "activation");
                if (activation_data && cJSON_IsObject(activation_data))
                {
                    // Handle activation data if present
                    cJSON *activation_challenge = cJSON_GetObjectItem(activation_data, "challenge");
                    if (activation_challenge && cJSON_IsString(activation_challenge))
                    {
                        activation_challenge_ = cJSON_GetStringValue(activation_challenge);
                        has_activation_challenge_ = true;
                    }

                    cJSON *activation_version = cJSON_GetObjectItem(activation_data, "version");
                    if (activation_version && cJSON_IsString(activation_version))
                    {
                        // Store activation version if needed
                        std::string activation_ver = cJSON_GetStringValue(activation_version);
                        ESP_LOGI(TAG, "Activation version: %s", activation_ver.c_str());
                    }
                }

                // Check for MQTT configuration
                cJSON *mqtt_config = cJSON_GetObjectItem(json, "mqtt");
                if (mqtt_config && cJSON_IsObject(mqtt_config))
                {
                    // Handle MQTT configuration updates
                    ESP_LOGI(TAG, "MQTT configuration received");
                    // This would typically involve updating settings
                }

                // Mark that we have a new version ready for download
                has_new_version_ = true;
            }
            else
            {
                ESP_LOGW(TAG, "New version found but no firmware URL provided");
            }
        }
        else
        {
            ESP_LOGI(TAG, "Current version is up to date");
            has_new_version_ = false;
        }
    }
    else
    {
        ESP_LOGW(TAG, "No version information in response");
    }

    // Cleanup
    cJSON_Delete(json);

    return ESP_OK;
}

