bool Ota::Upgrade(const std::string &firmware_url, std::function<void(int progress, size_t speed)> callback)
{
    ESP_LOGI(TAG, "Starting firmware upgrade from URL: %s", firmware_url.c_str());

    // Create HTTP client
    auto http = SetupHttp();

    // Open HTTP connection
    if (!http->Open("GET", firmware_url))
    {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection, code=0x%x", last_error);
        return false;
    }

    // Get content length for progress tracking
    auto content_length = http->GetContentLength();
    if (content_length <= 0)
    {
        ESP_LOGE(TAG, "Failed to get content length");
        http->Close();
        return false;
    }

    // Get OTA partition
    const esp_partition_t *ota_partition = esp_ota_get_next_update_partition(NULL);
    if (ota_partition == NULL)
    {
        ESP_LOGE(TAG, "Failed to get OTA partition");
        http->Close();
        return false;
    }

    ESP_LOGI(TAG, "Writing firmware to partition: %s", ota_partition->label);

    // Start OTA update
    esp_ota_handle_t ota_handle;
    esp_err_t err = esp_ota_begin(ota_partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_begin failed, error=0x%x", err);
        http->Close();
        return false;
    }

    // Download and write firmware
    std::vector<uint8_t> buffer(4096);
    size_t downloaded = 0;
    size_t last_speed_calc = 0;
    uint32_t start_time = esp_timer_get_time() / 1000; // milliseconds

    while (downloaded < content_length)
    {
        size_t to_read = std::min(buffer.size(), static_cast<size_t>(content_length - downloaded));
        int bytes_read = http->Read(buffer.data(), to_read);

        if (bytes_read <= 0)
        {
            ESP_LOGE(TAG, "Failed to read from HTTP connection");
            esp_ota_end(ota_handle);
            http->Close();
            return false;
        }

        // Write to OTA partition
        err = esp_ota_write(ota_handle, buffer.data(), bytes_read);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "esp_ota_write failed, error=0x%x", err);
            esp_ota_end(ota_handle);
            http->Close();
            return false;
        }

        downloaded += bytes_read;

        // Calculate progress and speed
        int progress = (downloaded * 100) / content_length;

        // Calculate speed every 100ms
        uint32_t current_time = esp_timer_get_time() / 1000;
        if (current_time - start_time > 100 || downloaded >= content_length)
        {
            size_t time_diff = current_time - start_time;
            if (time_diff > 0)
            {
                size_t speed = (downloaded * 1000) / time_diff; // bytes per second
                if (callback)
                {
                    callback(progress, speed);
                }
            }
            start_time = current_time;
        }
    }

    // End OTA operation
    err = esp_ota_end(ota_handle);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_end failed, error=0x%x", err);
        http->Close();
        return false;
    }

    // Set the new OTA partition as the boot partition
    err = esp_ota_set_boot_partition(ota_partition);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed, error=0x%x", err);
        http->Close();
        return false;
    }

    http->Close();

    ESP_LOGI(TAG, "Firmware upgrade completed successfully");
    return true;
}

std::vector<int> Ota::ParseVersion(const std::string &version)
{
    std::vector<int> result;
    std::stringstream ss(version);
    std::string item;

    while (std::getline(ss, item, '.')) {
        try {
            result.push_back(std::stoi(item));
        } catch (const std::exception&) {
            // If conversion fails, push 0 or handle appropriately
            result.push_back(0);
        }
    }

    return result;
}

bool Ota::IsNewVersionAvailable(const std::string &currentVersion, const std::string &newVersion)
{
    // Parse both version strings into vectors of integers
    auto currentSegments = ParseVersion(currentVersion);
    auto newSegments = ParseVersion(newVersion);

    // Compare version segments one by one
    size_t minSize = std::min(currentSegments.size(), newSegments.size());

    for (size_t i = 0; i < minSize; ++i)
    {
        if (newSegments[i] > currentSegments[i])
        {
            return true;  // New version is greater
        }
        else if (newSegments[i] < currentSegments[i])
        {
            return false; // New version is smaller
        }
        // If equal, continue to next segment
    }

    // If we've reached here, all compared segments were equal
    // Check if new version has more segments (e.g., 1.2 vs 1.2.0)
    // or if new version has more detailed version (e.g., 1.2.1 vs 1.2)
    return newSegments.size() > currentSegments.size();
}

std::string Ota::GetActivationPayload()
{
    if (!has_serial_number_)
    {
        // Return empty JSON object if no serial number is available
        return "{}";
    }

    // Create the JSON payload
    cJSON *root = cJSON_CreateObject();
    if (root == NULL)
    {
        return "{}";
    }

    // Add serial number
    cJSON_AddStringToObject(root, "serial_number", serial_number_.c_str());

    // Add challenge
    if (has_activation_challenge_)
    {
        cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());
    }

    // Generate HMAC-SHA256 signature
    #ifdef SOC_HMAC_SUPPORTED
    {
        // Create the message to be signed (serial_number + challenge)
        std::string message = serial_number_;
        if (has_activation_challenge_)
        {
            message += activation_challenge_;
        }

        // Prepare HMAC context
        esp_hmac_context_t hmac_ctx;
        esp_err_t err = esp_hmac_start(&hmac_ctx, ESP_HMAC_SHA256, NULL, 0);
        if (err == ESP_OK)
        {
            err = esp_hmac_update(&hmac_ctx, message.data(), message.length());
            if (err == ESP_OK)
            {
                uint8_t hmac_result[32]; // SHA256 produces 32 bytes
                err = esp_hmac_finish(&hmac_ctx, hmac_result, 32);
                if (err == ESP_OK)
                {
                    // Convert HMAC result to hex string
                    std::string signature;
                    signature.reserve(64);
                    for (int i = 0; i < 32; i++)
                    {
                        char hex[3];
                        snprintf(hex, sizeof(hex), "%02x", hmac_result[i]);
                        signature += hex;
                    }
                    cJSON_AddStringToObject(root, "signature", signature.c_str());
                }
            }
        }
    }
    #endif

    // Convert to JSON string
    char *json_string = cJSON_Print(root);
    std::string result = json_string ? json_string : "{}";

    // Clean up
    cJSON_Delete(root);
    if (json_string)
    {
        free(json_string);
    }

    return result;
}

