std::string SystemInfo::GetMacAddress()
{
    uint8_t mac[6];

    // Read the Wi-Fi station MAC address
    if (esp_read_mac(mac, ESP_MAC_WIFI_STA) != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to read MAC address");
        return "";
    }

    // Format the MAC address as XX:XX:XX:XX:XX:XX
    char mac_str[18]; // 17 characters + null terminator
    snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);

    return std::string(mac_str);
}

std::string SystemInfo::GetUserAgent()
{
    const esp_app_desc_t *app_desc = esp_ota_get_app_description();
    if (app_desc == NULL) {
        ESP_LOGE(TAG, "Failed to get application description");
        return std::string("unknown/0.0.0");
    }

    // Get board name from CONFIG_IDF_TARGET
    std::string board_name = std::string(CONFIG_IDF_TARGET);

    // Construct user agent string in format "BOARD_NAME/version"
    std::string user_agent = board_name + "/" + std::string(app_desc->version);

    return user_agent;
}

