esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait)
{
#if configGENERATE_RUN_TIME_STATS == 1
    // Get the number of tasks
    UBaseType_t task_count = uxTaskGetNumberOfTasks();

    // Allocate buffers for runtime stats
    char *stats_buffer = new char[task_count * 50];
    if (stats_buffer == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate memory for stats buffer");
        return ESP_FAIL;
    }

    // Get initial runtime stats
    vTaskGetRunTimeStats(stats_buffer);

    // Delay for the specified time
    vTaskDelay(xTicksToWait);

    // Get final runtime stats
    vTaskGetRunTimeStats(stats_buffer);

    // Print the results
    ESP_LOGI(TAG, "Task CPU Usage Statistics:");
    ESP_LOGI(TAG, "%s", stats_buffer);

    delete[] stats_buffer;

    return ESP_OK;
#else
    ESP_LOGW(TAG, "Runtime stats not enabled (configGENERATE_RUN_TIME_STATS not set)");
    return ESP_ERR_NOT_SUPPORTED;
#endif
}

void SystemInfo::PrintTaskList()
{
    // Get the length of the task list string
    uint32_t task_list_length = 0;
    char *task_list_buffer = NULL;

    // First call to get the required buffer size
    vTaskList(task_list_buffer);

    // Get the actual required buffer size (this is a bit tricky with vTaskList)
    // We'll use a reasonable buffer size for now
    task_list_length = 2048; // Reasonable size for task list

    // Allocate buffer for task list
    task_list_buffer = (char *)malloc(task_list_length);
    if (task_list_buffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task list");
        return;
    }

    // Clear the buffer
    memset(task_list_buffer, 0, task_list_length);

    // Get the task list
    vTaskList(task_list_buffer);

    // Log the task list
    ESP_LOGI(TAG, "Task List:\n%s", task_list_buffer);

    // Free allocated memory
    free(task_list_buffer);
}

