            .ws = BOARD_I2S_WS_PIN,
            .dout = I2S_GPIO_UNUSED,
            .din = BOARD_I2S_DIN_PIN,
        },
    };

    // Create I2S channels if not already created
    if (tx_handle_ == nullptr) {
        esp_err_t ret = i2s_new_channel(&tx_chan_cfg, &tx_handle_, NULL);
