        }
    }

    if (rx_handle_ == nullptr) {
        esp_err_t ret = i2s_new_channel(&rx_chan_cfg, &rx_handle_, NULL);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to create RX channel: %s", esp_err_to_name(ret));
            return;
        }
    }

    // Apply output volume setting
    SetOutputVolume(output_volume_);

    // Apply input gain setting
    SetInputGain(input_gain_);

    // Enable input/output paths based on their enabled status
    if (input_enabled_) {
        EnableInput(true);
    }

    if (output_enabled_) {
        EnableOutput(true);
    }

    ESP_LOGI(TAG, "Audio codec started successfully");
}

void AudioCodec::SetOutputVolume(int volume)
{
    // Validate volume range (assuming 0-100 range)
    if (volume < 0) {
        volume = 0;
    } else if (volume > 100) {
        volume = 100;
    }

    // Update internal volume state
    output_volume_ = volume;

    // Save to non-volatile storage for persistence
    Settings settings("audio", true);
    settings.SetInt("output_volume", output_volume_);

    // Log the change for debugging purposes
    ESP_LOGI(TAG, "Output volume set to %d", output_volume_);
}

