Es8388AudioCodec::~Es8388AudioCodec()
{
    // Close input device if open
    if (input_dev_) {
        esp_codec_dev_close(input_dev_);
        input_dev_ = nullptr;
    }

    // Close output device if open
    if (output_dev_) {
        esp_codec_dev_close(output_dev_);
        output_dev_ = nullptr;
    }

    // Delete codec interface
    if (codec_if_) {
        audio_codec_delete(codec_if_);
        codec_if_ = nullptr;
    }

    // Delete GPIO interface
    if (gpio_if_) {
        audio_codec_delete_gpio(gpio_if_);
        gpio_if_ = nullptr;
    }

    // Delete control interface
    if (ctrl_if_) {
        audio_codec_delete_ctrl(ctrl_if_);
        ctrl_if_ = nullptr;
    }

    // Delete data interface
    if (data_if_) {
        audio_codec_delete_data(data_if_);
        data_if_ = nullptr;
    }

    // Delete I2S channels
    if (tx_handle_) {
        i2s_del_channel(tx_handle_);
        tx_handle_ = nullptr;
    }
    if (rx_handle_) {
        i2s_del_channel(rx_handle_);
        rx_handle_ = nullptr;
    }
}

void Es8388AudioCodec::CreateDuplexChannels(gpio_num_t mclk, gpio_num_t bclk, gpio_num_t ws, gpio_num_t dout, gpio_num_t din)
{
    // Configure I2S master mode for full-duplex operation
    i2s_config_t i2s_config = {
        .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX | I2S_MODE_RX),
        .sample_rate = input_sample_rate_,  // Use input sample rate for consistency
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT,
        .communication_format = (i2s_comm_format_t)(I2S_COMM_FORMAT_I2S | I2S_COMM_FORMAT_I2S_MSB),
        .dma_buf_count = 8,
        .dma_buf_len = 64,
        .use_apll = false,
        .tx_desc_auto_clear = true,
        .fixed_mclk = 0,
        .mclk_multiple = I2S_MCLK_MULT_256,
        .bits_per_chan = I2S_BITS_PER_CHAN_16BIT,
    };

    // Configure I2S pin configuration
    i2s_pin_config_t pin_config = {
        .bck_io_num = bclk,
        .ws_io_num = ws,
        .data_out_num = dout,
        .data_in_num = din,
    };

    // Install and start I2S driver
    ESP_ERROR_CHECK(i2s_driver_install(I2S_NUM_0, &i2s_config, 0, NULL));

    // Set up I2S pins
    ESP_ERROR_CHECK(i2s_set_pin(I2S_NUM_0, &pin_config));

    // Set MCLK pin as output and configure it
    if (mclk != GPIO_NUM_NC) {
        gpio_config_t mclk_config = {
            .pin_bit_mask = (1ULL << mclk),
            .mode = GPIO_MODE_OUTPUT,
            .pull_up_en = GPIO_PULLUP_DISABLE,
            .pull_down_en = GPIO_PULLDOWN_DISABLE,
            .intr_type = GPIO_INTR_DISABLE,
        };
        gpio_config(&mclk_config);
        // Initialize MCLK to low state
        gpio_set_level(mclk, 0);
    }

    // Get handles for RX and TX
    rx_handle_ = (void*)I2S_NUM_0;
    tx_handle_ = (void*)I2S_NUM_0;
}

