void Es8388AudioCodec::SetOutputVolume(int volume)
{
    // Store the new volume in the internal state
    output_volume_ = volume;

    // Ensure volume is within valid range (0-100)
    if (volume < 0) {
        volume = 0;
    } else if (volume > 100) {
        volume = 100;
    }

    // Set the software volume using the codec device
    if (output_dev_) {
        ESP_ERROR_CHECK(esp_codec_dev_set_out_vol(output_dev_, volume));
    }

    // Update hardware registers for analog output volume
    // Convert volume percentage to register value (0-31 for ES8388)
    uint8_t reg_val = (uint8_t)((volume * 31) / 100);

    // Set analog output volume registers for headphone and speaker
    uint8_t regs[] = {46, 47, 48, 49}; // HP_LVOL, HP_RVOL, SPK_LVOL, SPK_RVOL

    // Ensure we don't set negative values
    if (reg_val > 31) {
        reg_val = 31;
    }

    for (uint8_t reg : regs) {
        if (ctrl_if_ && ctrl_if_->write_reg) {
            ctrl_if_->write_reg(ctrl_if_, reg, 1, &reg_val, 1);
        }
    }
}

