void Es8388AudioCodec::EnableInput(bool enable)
{
    std::lock_guard<std::mutex> lock(data_if_mutex_);
    if (enable == input_enabled_)
    {
        return;
    }

    if (enable)
    {
        esp_codec_dev_sample_info_t fs = {
            .bits_per_sample = 16,
            .channel = input_channels_,
            .channel_mask = 0,
            .sample_rate = (uint32_t)input_sample_rate_,
            .mclk_multiple = 0,
        };

        ESP_ERROR_CHECK(esp_codec_dev_open(input_dev_, &fs));

        // Apply input gain - using either fixed value or adjustable gain
        uint8_t gain = input_gain_;
        // For ES8388, typical input gain register is 0x10 (INPGAL) and 0x11 (INPGAR)
        // Setting gain to 24dB as default
        ctrl_if_->write_reg(ctrl_if_, 0x10, 1, &gain, 1);  // Left channel input PGA
        ctrl_if_->write_reg(ctrl_if_, 0x11, 1, &gain, 1);  // Right channel input PGA

        // Also set ADC gain if needed (register 0x12 for ADC left and 0x13 for ADC right)
        // This is typically used for microphone gain adjustment
        uint8_t adc_gain = 0x00;  // Default ADC gain
        ctrl_if_->write_reg(ctrl_if_, 0x12, 1, &adc_gain, 1);
        ctrl_if_->write_reg(ctrl_if_, 0x13, 1, &adc_gain, 1);
    }
    else
    {
        ESP_ERROR_CHECK(esp_codec_dev_close(input_dev_));
    }

    AudioCodec::EnableInput(enable);
}

