void Es8388AudioCodec::EnableOutput(bool enable)
{
    std::lock_guard<std::mutex> lock(data_if_mutex_);
    if (enable == output_enabled_)
    {
        return;
    }
    if (enable)
    {
        esp_codec_dev_sample_info_t fs = {
            .bits_per_sample = 16,
            .channel = 2, // Stereo output
            .channel_mask = ESP_CODEC_DEV_MAKE_CHANNEL_MASK(0) | ESP_CODEC_DEV_MAKE_CHANNEL_MASK(1),
            .sample_rate = (uint32_t)output_sample_rate_,
            .mclk_multiple = 0,
        };
        ESP_ERROR_CHECK(esp_codec_dev_open(output_dev_, &fs));

        // Set default volume (assuming it was set previously or use default)
        // This would typically be called with a specific volume value
        // For now, we'll assume volume is handled separately

        // Activate power amplifier if pin is defined
        if (pa_pin_ != GPIO_NUM_NC)
        {
            gpio_config_t io_conf = {};
            io_conf.pin_bit_mask = (1ULL << pa_pin_);
            io_conf.mode = GPIO_MODE_OUTPUT;
            io_conf.pull_up_en = GPIO_PULLUP_DISABLE;
            io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE;
            io_conf.intr_type = GPIO_INTR_DISABLE;
            ESP_ERROR_CHECK(gpio_config(&io_conf));
            gpio_set_level(pa_pin_, 1);
        }
    }
    else
    {
        ESP_ERROR_CHECK(esp_codec_dev_close(output_dev_));

        // Deactivate power amplifier if pin is defined
        if (pa_pin_ != GPIO_NUM_NC)
        {
            gpio_set_level(pa_pin_, 0);
        }
    }
    AudioCodec::EnableOutput(enable);
}

int Es8388AudioCodec::Read(int16_t *dest, int samples)
{
    if (!input_enabled_ || !input_dev_ || dest == nullptr)
    {
        return 0;
    }

    std::lock_guard<std::mutex> lock(data_if_mutex_);

    size_t bytes_to_read = samples * sizeof(int16_t);
    size_t bytes_read = 0;

    esp_err_t ret = esp_codec_dev_read(input_dev_, dest, bytes_to_read, &bytes_read);

    if (ret != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to read audio data: %s", esp_err_to_name(ret));
        return 0;
    }

    // Return the number of samples read (convert bytes to samples)
    return bytes_read / sizeof(int16_t);
}

int Es8388AudioCodec::Write(const int16_t *data, int samples)
{
    if (!output_enabled_)
    {
        ESP_LOGW(TAG, "Output is not enabled");
        return 0;
    }

    if (output_dev_ == nullptr)
    {
        ESP_LOGE(TAG, "Output device is not initialized");
        return 0;
    }

    if (data == nullptr)
    {
        ESP_LOGE(TAG, "Data pointer is null");
        return 0;
    }

    // Convert samples to bytes for transmission
    size_t bytes_to_write = samples * sizeof(int16_t);

    // Write the data to the output device
    esp_err_t ret = esp_codec_dev_write(output_dev_, (void *)data, bytes_to_write);

    if (ret != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to write audio data, err: %d", ret);
        return 0;
    }

    // Return the number of samples written
    return samples;
}

