void AudioDebugger::Feed(const std::vector<int16_t> &data)
{
#if CONFIG_USE_AUDIO_DEBUGGER
    if (udp_sockfd_ >= 0 && data.size() > 0)
    {
        ssize_t sent_bytes = sendto(udp_sockfd_, 
                                   data.data(), 
                                   data.size() * sizeof(int16_t), 
                                   0, 
                                   (struct sockaddr*)&udp_server_addr_, 
                                   sizeof(udp_server_addr_));

        if (sent_bytes < 0)
        {
            ESP_LOGE(TAG, "Failed to send audio data via UDP: %d", errno);
        }
        else
        {
            ESP_LOGD(TAG, "Sent %zd bytes of audio data via UDP", sent_bytes);
        }
    }
    else if (data.empty())
    {
        ESP_LOGW(TAG, "No audio data to send");
    }
    else
