bool AfeWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list)
{
    if (codec == nullptr || models_list == nullptr) {
        ESP_LOGE(TAG, "Invalid input parameters");
        return false;
    }

    codec_ = codec;

    // Initialize the audio codec
    if (codec_->Initialize() != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize audio codec");
        return false;
    }

    // Load wake word models
    models_ = esp_srmodel_init(models_list);
    if (models_ == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize wake word models");
        return false;
    }

    // Get AFE interface
    afe_iface_ = esp_afe_sr_get_interface();
    if (afe_iface_ == nullptr) {
        ESP_LOGE(TAG, "Failed to get AFE interface");
        return false;
    }

    // Initialize AFE data structure
    afe_data_ = afe_iface_->create(models_, codec_);
    if (afe_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create AFE data");
        return false;
    }

    // Configure AFE with appropriate settings for echo cancellation
    // and other processing parameters
    if (afe_iface_->set_config(afe_data_, AFE_CONFIG_ECHO_CANCEL, 1) != ESP_OK) {
        ESP_LOGW(TAG, "Failed to enable echo cancellation");
        // Continue without echo cancellation, it's not critical
    }

    // Initialize wake words list from models
    wake_words_.clear();
    for (int i = 0; i < models_list->model_num; i++) {
        wake_words_.push_back(models_list->model[i].name);
    }

    // Allocate memory for wake word PCM data storage
    wake_word_pcm_.clear();

    // Create and start the audio detection task
    BaseType_t result = xTaskCreate(
        [](void *arg) {
            auto this_ = (AfeWakeWord*)arg;
            this_->AudioDetectionTask();
        },
        "afe_wake_word",
        4096,
        this,
        5,
        nullptr
    );

    if (result != pdPASS) {
        ESP_LOGE(TAG, "Failed to create audio detection task");
        return false;
    }

    ESP_LOGI(TAG, "AfeWakeWord initialized successfully");
    return true;
}

void AfeWakeWord::Stop()
{
    // Clear the detection running event flag to stop the detection process
    xEventGroupClearBits(event_group_, DETECTION_RUNNING_EVENT);

    // Reset the audio front-end buffer if initialized
    if (afe_data_ != nullptr)
    {
        // Reset the audio front-end to clear any buffered data
        afe_iface_->reset(afe_data_);
    }
}

