void AfeWakeWord::StoreWakeWordData(const int16_t *data, size_t samples)
{
    // Convert the raw data into a vector and add to our deque
    std::vector<int16_t> new_samples(data, data + samples);

    // Add the new samples to the deque
    wake_word_pcm_.push_back(std::move(new_samples));

    // Maintain approximately 2 seconds of audio data
    // Assuming 16000 Hz sample rate, 2 seconds = 32000 samples
    // We'll keep a reasonable number of chunks to approximate 2 seconds
    const size_t max_samples = 32000;
    size_t total_samples = 0;

    // Count total samples to determine if we need to remove old chunks
    for (const auto& chunk : wake_word_pcm_) {
        total_samples += chunk.size();
    }

    // Remove oldest chunks until we're under the limit
    while (total_samples > max_samples && !wake_word_pcm_.empty()) {
        total_samples -= wake_word_pcm_.front().size();
        wake_word_pcm_.pop_front();
    }
}

