bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t> &opus)
{
    std::unique_lock<std::mutex> lock(wake_word_mutex_);

    // Wait until there's data available or we have a sentinel (empty vector)
    wake_word_cv_.wait(lock, [this] { 
        return !wake_word_opus_.empty(); 
    });

    // Check if we have valid data (not the sentinel)
    if (wake_word_opus_.empty()) {
        return false;
    }

    // Get the first element and remove it from the queue
    opus = std::move(wake_word_opus_.front());
    wake_word_opus_.pop_front();

    // If this was the sentinel (empty vector), we're done
    if (opus.empty()) {
        return false;
    }

    return true;
}

