void CustomWakeWord::ParseWakenetModelConfig()
{
    // Get the index.json asset
    const esp_partition_t *partition = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_SPIFFS, "assets");
    if (partition == nullptr) {
        ESP_LOGE(TAG, "Failed to find assets partition");
        return;
    }

    // Try to load index.json from assets
    const char* index_json_path = "index.json";
    FILE* file = fopen(index_json_path, "r");
    if (file == nullptr) {
        ESP_LOGE(TAG, "Failed to open index.json");
        return;
    }

    // Read the entire file content
    fseek(file, 0, SEEK_END);
    long file_size = ftell(file);
    fseek(file, 0, SEEK_SET);

    char* json_content = (char*)malloc(file_size + 1);
    if (json_content == nullptr) {
        fclose(file);
        ESP_LOGE(TAG, "Failed to allocate memory for JSON content");
        return;
    }

    size_t bytes_read = fread(json_content, 1, file_size, file);
    fclose(file);
    json_content[bytes_read] = '\0';

    // Parse JSON
    cJSON* root = cJSON_Parse(json_content);
    free(json_content);

    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse index.json: %s", cJSON_GetErrorPtr());
        return;
    }

    // Extract language
    cJSON* language_item = cJSON_GetObjectItem(root, "language");
    if (language_item != nullptr && cJSON_IsString(language_item)) {
        language_ = cJSON_GetStringValue(language_item);
    } else {
        language_ = "cn"; // default language
    }

    // Extract duration
    cJSON* duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item != nullptr && cJSON_IsNumber(duration_item)) {
        duration_ = cJSON_GetNumberValue(duration_item);
    } else {
        duration_ = 30; // default duration in ms
    }

    // Extract threshold
    cJSON* threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item != nullptr && cJSON_IsNumber(threshold_item)) {
        threshold_ = cJSON_GetNumberValue(threshold_item);
    } else {
        threshold_ = 0.5f; // default threshold
    }

    // Extract commands
    cJSON* commands_item = cJSON_GetObjectItem(root, "commands");
    if (commands_item != nullptr && cJSON_IsArray(commands_item)) {
        commands_.clear();
        int array_size = cJSON_GetArraySize(commands_item);
        for (int i = 0; i < array_size; i++) {
            cJSON* command_obj = cJSON_GetArrayItem(commands_item, i);
            if (command_obj != nullptr) {
                cJSON* command_name = cJSON_GetObjectItem(command_obj, "command");
                cJSON* display_text = cJSON_GetObjectItem(command_obj, "display");
                cJSON* action = cJSON_GetObjectItem(command_obj, "action");

                if (command_name != nullptr && cJSON_IsString(command_name)) {
                    std::string cmd = cJSON_GetStringValue(command_name);
                    std::string disp = display_text ? cJSON_GetStringValue(display_text) : cmd;
                    std::string act = action ? cJSON_GetStringValue(action) : "";

                    commands_.push_back({cmd, disp, act});
                    ESP_LOGI(TAG, "Parsed command: command='%s', display='%s', action='%s'", 
