bool CustomWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list)
{
    // Store the codec pointer
    codec_ = codec;

    // Parse the wakenet model configuration from index.json
    ParseWakenetModelConfig();

    // Initialize the models list
    models_ = models_list;

    // Check if models are valid
    if (models_ == nullptr) {
        ESP_LOGE(TAG, "Invalid models list");
        return false;
    }

    // Find and load the multinet model based on language
    const char *model_name = nullptr;
    if (language_ == "cn") {
        model_name = "multinet_cn";
    } else if (language_ == "en") {
        model_name = "multinet_en";
    } else {
        model_name = "multinet_cn"; // default to Chinese
    }

    // Initialize multinet interface
    multinet_ = esp_mn_get_interface(model_name);
    if (multinet_ == nullptr) {
        ESP_LOGE(TAG, "Failed to get multinet interface for model: %s", model_name);
        return false;
    }

    // Load the model data
    multinet_model_data_ = multinet_->create(models_, model_name);
    if (multinet_model_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create multinet model data");
        return false;
    }

    // Set the detection threshold
    if (multinet_->set_threshold(multinet_model_data_, threshold_) != ESP_OK) {
        ESP_LOGW(TAG, "Failed to set detection threshold, using default");
    }

    // Set the detection duration
    if (multinet_->set_duration(multinet_model_data_, duration_) != ESP_OK) {
        ESP_LOGW(TAG, "Failed to set detection duration, using default");
    }

    // Initialize the wake word encode task stack and buffer
    const size_t stack_size = 4096 * 7;
    wake_word_encode_task_stack_ = (StackType_t *)heap_caps_malloc(stack_size, MALLOC_CAP_SPIRAM);
    if (wake_word_encode_task_stack_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate wake word encode task stack");
        return false;
    }

    wake_word_encode_task_buffer_ = (StaticTask_t *)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL);
    if (wake_word_encode_task_buffer_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate wake word encode task buffer");
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
        return false;
    }

    ESP_LOGI(TAG, "Custom wake word initialized successfully");
    return true;
}

