void CustomWakeWord::Feed(const std::vector<int16_t> &data)
{
    if (!running_ || multinet_ == nullptr || multinet_model_data_ == nullptr) {
        return;
    }

    // Handle stereo input by extracting left channel
    std::vector<int16_t> mono_data;
    if (data.size() % 2 == 0) {
        // Assuming stereo data, extract left channel (every other sample starting from 0)
        mono_data.reserve(data.size() / 2);
        for (size_t i = 0; i < data.size(); i += 2) {
            mono_data.push_back(data[i]);
        }
    } else {
        // Already mono or unknown format, use as-is
        mono_data = data;
    }

    // Store the audio data for potential wake word recording
    StoreWakeWordData(mono_data);

    // Run detection on the audio data
    int result = multinet_->detect(multinet_model_data_, mono_data.data());

    // Check if wake word was detected
    if (result > 0 && result <= static_cast<int>(commands_.size())) {
        // Get the detected wake word name
        const std::string &detected_wake_word = commands_[result - 1].command;

        // Update last detected wake word
        last_detected_wake_word_ = detected_wake_word;

        // Stop processing until reactivated
        running_ = false;

        // Trigger the callback if it exists
        if (wake_word_detected_callback_) {
            wake_word_detected_callback_(detected_wake_word);
        }
    }
}

