void CustomWakeWord::StoreWakeWordData(const std::vector<int16_t> &data)
{
    if (multinet_model_data_ == nullptr)
    {
        return;
    }

    // Add the new data to the buffer
    wake_word_pcm_.push_back(data);

    // Calculate the maximum number of samples for 2 seconds
    // Using the sample rate from the multinet model
    size_t sample_chunk_size = multinet_->get_samp_chunksize(multinet_model_data_);
    size_t max_samples = 16000 * 2; // 2 seconds at 16000 Hz

    // Remove old data until we're within the 2-second limit
    while (wake_word_pcm_.size() > 0)
    {
        size_t total_samples = 0;
        for (const auto& chunk : wake_word_pcm_)
        {
            total_samples += chunk.size();
        }

        // If we exceed 2 seconds, remove the oldest chunk
        if (total_samples > max_samples)
        {
            wake_word_pcm_.pop_front();
        }
        else
        {
            break;
        }
    }
}

