void SetOutputState(uint8_t bit, uint8_t level)
{
    // Read current output register value
    uint8_t current_value = ReadReg(0x07);

    // Set or clear the specific bit based on level
    if (level) {
        // Set the bit high
        current_value |= (1 << bit);
    } else {
        // Set the bit low
        current_value &= ~(1 << bit);
    }

    // Write the updated value back to the output register
    WriteReg(0x07, current_value);
}

