void InitializeCamera()
{
    // Configure camera power and reset signals through I/O expander
    // Power down camera first
    xl9555_->SetOutputState(9, 0);  // Camera power down (assuming bit 9 controls power)

    // Wait for power to stabilize
    vTaskDelay(pdMS_TO_TICKS(10));

    // Reset camera
    xl9555_->SetOutputState(10, 0);  // Camera reset low
    vTaskDelay(pdMS_TO_TICKS(10));

    // Release reset
    xl9555_->SetOutputState(10, 1);  // Camera reset high
    vTaskDelay(pdMS_TO_TICKS(10));

    // Enable camera power
    xl9555_->SetOutputState(9, 1);  // Camera power up

    // Wait for camera to stabilize
    vTaskDelay(pdMS_TO_TICKS(50));

    // Configure camera pins for DVP interface
    esp_video_init_config_t config = {};

    // Set up DVP pin configuration
    config.dvp_pclk = CAMERA_PIN_PCLK;
    config.dvp_vsync = CAMERA_PIN_VSYNC;
    config.dvp_href = CAMERA_PIN_HREF;
    config.dvp_xclk = CAMERA_PIN_XCLK;
    config.dvp_siod = CAMERA_PIN_SIOD;
    config.dvp_sioc = CAMERA_PIN_SIOC;

    // Configure data pins
    config.dvp_d0 = CAMERA_PIN_D0;
    config.dvp_d1 = CAMERA_PIN_D1;
    config.dvp_d2 = CAMERA_PIN_D2;
    config.dvp_d3 = CAMERA_PIN_D3;
    config.dvp_d4 = CAMERA_PIN_D4;
    config.dvp_d5 = CAMERA_PIN_D5;
    config.dvp_d6 = CAMERA_PIN_D6;
    config.dvp_d7 = CAMERA_PIN_D7;

    // Set clock frequency
    config.xclk_freq_hz = CAMERA_XCLK_FREQ;

    // Set pixel format and frame size
    config.pixel_format = PIXFORMAT_YUV422;
    config.frame_size = FRAMESIZE_QVGA;

    // Initialize camera with configuration
    camera_ = new Esp32Camera(config);
}

