FrequencyDetector::FrequencyDetector(float frequency, size_t window_size)
    : frequency_(frequency),
      window_size_(window_size)
{
    // Calculate frequency bin (the index in the DFT where the peak would occur)
    frequency_bin_ = frequency * static_cast<float>(window_size_);

    // Calculate angular frequency ω = 2πf/fs
    angular_frequency_ = 2.0f * static_cast<float>(M_PI) * frequency_;

    // Calculate coefficients for the Goertzel algorithm
    // cos(ω) and sin(ω)
    cos_coefficient_ = std::cos(angular_frequency_);
    sin_coefficient_ = std::sin(angular_frequency_);

    // Filter coefficient = 2 * cos(ω)
    filter_coefficient_ = 2.0f * cos_coefficient_;

    // Initialize state buffer with zeros (size = 2 for S[-1] and S[-2])
    state_buffer_.clear();
    state_buffer_.resize(2, 0.0f);
}

void FrequencyDetector::Reset()
{
    state_buffer_.clear();
    state_buffer_.push_back(0.0f);
    state_buffer_.push_back(0.0f);
}

