void FrequencyDetector::ProcessSample(float sample)
{
    // Apply the second-order IIR filter difference equation
    // S[n] = filter_coefficient_ * S[n-1] - S[n-2] + sample
    float s_current = filter_coefficient_ * state_buffer_[1] - state_buffer_[0] + sample;

    // Update state buffer: shift elements and add new value
    // Move S[-1] to S[-2]
    state_buffer_[0] = state_buffer_[1];
    // Set new S[-1] to current filtered value
    state_buffer_[1] = s_current;
}

float FrequencyDetector::GetAmplitude() const
{
    // If there are fewer than 2 samples in the buffer, return 0
    if (state_buffer_.size() < 2)
    {
        return 0.0f;
    }

    // Get the previous two samples (S[-1] and S[-2])
    float s_minus_1 = state_buffer_.front(); // S[-1]
    state_buffer_.pop_front();
    float s_minus_2 = state_buffer_.front(); // S[-2]
    state_buffer_.push_front(s_minus_1);     // Put S[-1] back

    // Apply Goertzel algorithm to compute real and imaginary components
    // Real part: R = s[-1] * cos(w) - s[-2] * sin(w)
    float real_part = s_minus_1 * cos_coefficient_ - s_minus_2 * sin_coefficient_;

    // Imaginary part: I = s[-1] * sin(w) + s[-2] * cos(w)
    float imaginary_part = s_minus_1 * sin_coefficient_ + s_minus_2 * cos_coefficient_;

    // Calculate amplitude: sqrt(real^2 + imaginary^2)
    float amplitude = std::sqrt(real_part * real_part + imaginary_part * imaginary_part);

    // Normalize by half the window size as specified in the requirement
    amplitude /= (static_cast<float>(window_size_) * 0.5f);

    return amplitude;
}

