std::vector<float> AudioSignalProcessor::ProcessAudioSamples(const std::vector<float> &samples)
{
    std::vector<float> probabilities;

    // Process each sample
    for (float sample : samples)
    {
        // Add sample to input buffer
        input_buffer_.push_back(sample);

        // If buffer is full, process the window
        if (input_buffer_.size() >= input_buffer_size_)
        {
            // Process all samples in the current window with both detectors
            for (size_t i = 0; i < input_buffer_size_; ++i)
            {
                mark_detector_->ProcessSample(input_buffer_[i]);
                space_detector_->ProcessSample(input_buffer_[i]);
            }

            // Get amplitudes from both detectors
            float mark_amplitude = mark_detector_->GetAmplitude();
            float space_amplitude = space_detector_->GetAmplitude();

            // Calculate probability of mark tone presence
            // Simple approach: normalize the difference between mark and space amplitudes
            float amplitude_diff = mark_amplitude - space_amplitude;
            float amplitude_sum = mark_amplitude + space_amplitude;

            float probability = 0.0f;
            if (amplitude_sum > 0.0f)
            {
                probability = std::clamp(amplitude_diff / amplitude_sum, 0.0f, 1.0f);
            }

            probabilities.push_back(probability);

            // Remove the oldest sample from buffer
            input_buffer_.pop_front();
        }
    }

    return probabilities;
}

