bool AudioDataBuffer::ProcessProbabilityData(const std::vector<float> &probabilities, float threshold)
{
    // Process each probability value
    for (float probability : probabilities)
    {
        // Convert probability to bit (0 or 1) based on threshold
        uint8_t bit = (probability > threshold) ? 1 : 0;

        // Add bit to identifier buffer for detection
        identifier_buffer_.push_back(bit);

        // Keep identifier buffer within bounds
        if (identifier_buffer_.size() > identifier_buffer_size_)
        {
            identifier_buffer_.pop_front();
        }

        // Add bit to main bit buffer
        bit_buffer_.push_back(bit);

        // Keep bit buffer within bounds
        if (bit_buffer_.size() > max_bit_buffer_size_)
        {
            bit_buffer_.erase(bit_buffer_.begin());
        }

        // State machine logic
        switch (current_state_)
        {
            case DataReceptionState::kInactive:
                // Look for start identifier
                if (identifier_buffer_.size() >= start_of_transmission_.size())
                {
                    bool match = true;
                    for (size_t i = 0; i < start_of_transmission_.size(); ++i)
                    {
                        if (identifier_buffer_[identifier_buffer_.size() - start_of_transmission_.size() + i] != 
                            start_of_transmission_[i])
                        {
                            match = false;
                            break;
                        }
                    }

                    if (match)
                    {
                        current_state_ = DataReceptionState::kWaiting;
                        // Clear the bit buffer as we're starting fresh
                        bit_buffer_.clear();
                    }
                }
                break;

            case DataReceptionState::kWaiting:
                // Wait for confirmation that we're actually receiving data
                // This could involve checking for a few more bits or timeout logic
                // For now, transition to receiving after detecting start
                current_state_ = DataReceptionState::kReceiving;
                break;

            case DataReceptionState::kReceiving:
                // Continue receiving data until we find end identifier
                if (identifier_buffer_.size() >= end_of_transmission_.size())
                {
                    bool match = true;
                    for (size_t i = 0; i < end_of_transmission_.size(); ++i)
                    {
                        if (identifier_buffer_[identifier_buffer_.size() - end_of_transmission_.size() + i] != 
                            end_of_transmission_[i])
                        {
                            match = false;
                            break;
                        }
                    }

                    if (match)
                    {
                        // End transmission detected - process the data
                        // Convert bits to bytes
                        std::vector<uint8_t> bytes = ConvertBitsToBytes(bit_buffer_);

                        // Convert bytes to string
                        std::string received_text(bytes.begin(), bytes.end());

                        // Validate checksum if enabled
                        if (enable_checksum_validation_ && received_text.length() > 1)
                        {
                            // Extract checksum (last byte)
                            uint8_t calculated_checksum = CalculateChecksum(received_text.substr(0, received_text.length() - 1));
                            uint8_t received_checksum = static_cast<uint8_t>(received_text.back());

                            if (calculated_checksum == received_checksum)
                            {
                                decoded_text = received_text.substr(0, received_text.length() - 1);
                            }
                            else
                            {
                                ESP_LOGW(kLogTag, "Checksum mismatch, discarding data");
                                ClearBuffers();
                                current_state_ = DataReceptionState::kInactive;
                                return false;
                            }
                        }
                        else
                        {
                            // No checksum validation or not enough data
                            decoded_text = received_text;
                        }

                        ClearBuffers();
                        current_state_ = DataReceptionState::kInactive;
                        return true; // Complete data received
                    }
                }
                break;
        }
    }

    return false; // No complete data received yet
}

