std::vector<uint8_t> AudioDataBuffer::ConvertBitsToBytes(const std::vector<uint8_t> &bits) const
{
    std::vector<uint8_t> result;

    // Handle empty input
    if (bits.empty()) {
        return result;
    }

    // Process bits in groups of 8
    for (size_t i = 0; i < bits.size(); i += 8) {
        uint8_t byte = 0;

        // Process up to 8 bits for this byte
        for (size_t j = 0; j < 8 && (i + j) < bits.size(); ++j) {
            // Set the bit at position (7-j) in the byte
            // This assumes MSB first ordering (most significant bit first)
            if (bits[i + j] == 1) {
                byte |= (1 << (7 - j));
            }
        }

        result.push_back(byte);
    }

    return result;
}

