void Backlight::RestoreBrightness()
{
    Settings settings("display", true);
    int brightness = settings.GetInt("brightness", 0);

    // If brightness is zero or invalid, use minimum brightness of 10
    if (brightness <= 0 || brightness > 100) {
        brightness = 10;
    }

    SetBrightness(brightness, false);
}

void Backlight::SetBrightness(uint8_t brightness, bool permanent)
{
    // Clamp brightness to valid range [0, 100]
    if (brightness > 100) {
        brightness = 100;
    }

    // Prevent redundant updates
    if (brightness_ == brightness) {
        return;
    }

    // Save to settings if requested
    if (permanent) {
        Settings settings("display");
        settings.SetInt("brightness", brightness);
    }

    // Set up transition parameters
    target_brightness_ = brightness;

    // Calculate step size for smooth transition
    int16_t diff = target_brightness_ - brightness_;
    step_ = (diff > 0) ? 1 : -1;

    // Start transition timer if not already running
    if (transition_timer_ != nullptr) {
        // Stop any existing timer
        esp_timer_stop(transition_timer_);

        // Start new timer with short period for smooth transition
        esp_timer_start_periodic(transition_timer_, 20000); // 20ms period
    }
}

void Backlight::OnTransitionTimer()
{
    // Update current brightness by one step
    brightness_ += step_;

    // Check if we've reached the target brightness
    if ((step_ > 0 && brightness_ >= target_brightness_) || 
        (step_ < 0 && brightness_ <= target_brightness_))
    {
        // We've reached or passed the target, set exact value
        brightness_ = target_brightness_;

        // Stop the timer since transition is complete
        esp_timer_stop(transition_timer_);
    }

    // Update the actual hardware brightness
    SetBrightnessImpl(brightness_);
}

