std::string Board::GetSystemInfoJson()
{
    // Get system information from SystemInfo class
    auto chip_model = SystemInfo::GetChipModelName();
    auto flash_size = SystemInfo::GetFlashSize();
    auto mac_address = SystemInfo::GetMacAddress();
    auto min_free_heap = SystemInfo::GetMinimumFreeHeapSize();
    auto user_agent = SystemInfo::GetUserAgent();

    // Get application description
    auto app_desc = esp_app_get_description();

    // Build JSON string
    std::string json = "{";

    // Hardware details
    json += "\"hardware\":{";
    json += "\"chip_model\":\"" + chip_model + "\",";
    json += "\"flash_size\":" + std::to_string(flash_size) + ",";
    json += "\"mac\":\"" + mac_address + "\"";
    json += "},";

    // Application metadata
    json += "\"application\":{";
    json += "\"name\":\"" + std::string(BOARD_NAME) + "\",";
    json += "\"version\":\"" + std::string(app_desc->version) + "\",";
    json += "\"compile_time\":\"" + std::string(app_desc->date) + " " + std::string(app_desc->time) + "\"";
    json += "},";

    // Runtime information
    json += "\"runtime\":{";
    json += "\"min_free_heap\":" + std::to_string(min_free_heap) + ",";
    json += "\"uuid\":\"" + GetUuid() + "\"";
    json += "}";

    json += "}";

    return json;
}

