void WifiBoard::StartNetwork()
{
    // Initialize WiFi manager with predefined SSID prefix and language
    auto &wifi_manager = WifiManager::GetInstance();

    // Set up the unified event callback to handle various WiFi events
    wifi_manager.SetEventCallback([this](NetworkEvent event, const std::string &data) {
        this->OnNetworkEvent(event, data);
    });

    // Attempt to establish WiFi connection or enter configuration mode if needed
    TryWifiConnect();
}

