void WifiBoard::TryWifiConnect()
{
    auto &wifi_manager = WifiManager::GetInstance();
    auto &ssid_manager = SsidManager::GetInstance();

    // Check if we have any saved SSIDs
    auto ssids = ssid_manager.GetSsids();

    if (ssids.empty()) {
        // No saved SSIDs, delay briefly then enter config mode
        ESP_LOGI(TAG, "No saved SSIDs found, entering config mode");

        // Schedule config mode entry after a short delay
        Application::GetInstance().Schedule([this]() {
            StartWifiConfigMode();
        });
    } else {
        // We have saved SSIDs, try to connect
        ESP_LOGI(TAG, "Attempting to connect with saved SSIDs");

        // Start connection attempt with timeout
        esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000 * 1000);

        // Try to connect to the first available SSID
        auto ssid = ssids[0];
        wifi_manager.StartStation(ssid.ssid, ssid.password);
    }
}

