void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string &data)
{
    switch (event) {
        case NetworkEvent::Scanning:
            ESP_LOGI(TAG, "WiFi scanning");
            break;

        case NetworkEvent::Connecting:
            ESP_LOGI(TAG, "Connecting to WiFi network: %s", data.c_str());
            // Start connection timeout timer
            esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000ULL);
            break;

        case NetworkEvent::Connected:
            ESP_LOGI(TAG, "WiFi connected to network: %s", data.c_str());
            // Stop connection timeout timer
            esp_timer_stop(connect_timer_);
            // Clear config mode flag
            in_config_mode_ = false;
            // Release provisioning resources if needed
#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
            // If we were in config mode, stop BLUFI provisioning
            if (IsInWifiConfigMode()) {
                Blufi::GetInstance().deinit();
            }
#endif
            break;

        case NetworkEvent::Disconnected:
            ESP_LOGW(TAG, "WiFi disconnected");
            // Stop connection timeout timer
            esp_timer_stop(connect_timer_);
            // If we're not in config mode, try to reconnect
            if (!in_config_mode_) {
                TryWifiConnect();
            }
            break;

        case NetworkEvent::WifiConfigModeEnter:
            ESP_LOGI(TAG, "Entering WiFi configuration mode");
            in_config_mode_ = true;
            // Stop any ongoing connection attempt
            esp_timer_stop(connect_timer_);
            // Stop station if running
            WifiManager::GetInstance().StopStation();
            break;

        case NetworkEvent::WifiConfigModeExit:
            ESP_LOGI(TAG, "Exiting WiFi configuration mode");
            in_config_mode_ = false;
            // Stop any ongoing connection attempt
            esp_timer_stop(connect_timer_);
            // Try to reconnect to saved networks
            TryWifiConnect();
            break;

        default:
            ESP_LOGW(TAG, "Unknown network event: %d", static_cast<int>(event));
            break;
    }

    // Notify external callback if set
    if (network_event_callback_) {
        network_event_callback_(event, data);
    }
}

