const char *WifiBoard::GetNetworkStateIcon()
{
    auto &wifi = WifiManager::GetInstance();

    // Check if in configuration mode first
    if (in_config_mode_ || wifi.IsConfigMode())
    {
        return "cog";  // Configuration mode icon
    }

    // Check connection status
    if (!wifi.IsConnected())
    {
        return "wifi-slash";  // Disconnected icon
    }

    // Connected - determine signal strength
    int rssi = wifi.GetRssi();
    if (rssi >= -60)
    {
        return "wifi";  // Strong signal
    }
    else if (rssi >= -70)
    {
        return "wifi-half";  // Fair signal
    }
    else
    {
        return "wifi-low";  // Weak signal
    }
}

