std::string WifiBoard::GetBoardJson()
{
    auto &wifi = WifiManager::GetInstance();
    auto root = cJSON_CreateObject();

    // Add board type
    cJSON_AddStringToObject(root, "type", GetBoardType().c_str());

    // Add board name (using system info or default)
    auto &system_info = SystemInfo::GetInstance();
    cJSON_AddStringToObject(root, "name", system_info.GetDeviceName().c_str());

    // Add MAC address
    uint8_t mac[6];
    esp_efuse_mac_get_default(mac);
    char mac_str[18];
    snprintf(mac_str, sizeof(mac_str), "%02x:%02x:%02x:%02x:%02x:%02x",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    cJSON_AddStringToObject(root, "mac", mac_str);

    // Add Wi-Fi details when not in config mode
    if (!wifi.IsConfigMode())
    {
        // Add SSID
        cJSON_AddStringToObject(root, "ssid", wifi.GetSsid().c_str());

        // Add RSSI
        int rssi = wifi.GetRssi();
        cJSON_AddNumberToObject(root, "rssi", rssi);

        // Add channel
        int channel = wifi.GetChannel();
        cJSON_AddNumberToObject(root, "channel", channel);

        // Add IP address
        auto ip_info = wifi.GetIpInfo();
        if (ip_info.ip.addr != 0)
        {
            char ip_str[16];
            snprintf(ip_str, sizeof(ip_str), IPSTR, IP2STR(&ip_info.ip));
            cJSON_AddStringToObject(root, "ip", ip_str);
        }
    }

    // Add configuration mode status
    cJSON_AddBoolToObject(root, "config_mode", wifi.IsConfigMode());

    auto str = cJSON_PrintUnformatted(root);
    std::string result(str);
    cJSON_free(str);
    cJSON_Delete(root);

    return result;
}

