std::string WifiBoard::GetDeviceStatusJson()
{
    auto &wifi = WifiManager::GetInstance();
    auto &board = Board::GetInstance();

    std::string json = "{";

    // Add audio volume
    auto audio_codec = board.GetAudioCodec();
    if (audio_codec) {
        int volume = audio_codec->GetVolume();
        json += "\"volume\":" + std::to_string(volume) + ",";
    } else {
        json += "\"volume\":0,";
    }

    // Add screen brightness and theme
    auto display = board.GetDisplay();
    if (display) {
        int brightness = display->GetBrightness();
        json += "\"brightness\":" + std::to_string(brightness) + ",";

        // For theme, we'll use a default since it's not directly available
        // This would typically come from settings or application state
        json += "\"theme\":\"default\",";
    } else {
        json += "\"brightness\":0,\"theme\":\"default\",";
    }

    // Add battery info
    int battery_level = 0;
    bool charging = false;
    bool discharging = false;
    if (board.GetBatteryLevel(battery_level, charging, discharging)) {
        json += "\"battery\":" + std::to_string(battery_level) + ",";
        json += "\"charging\":" + std::string(charging ? "true" : "false") + ",";
        json += "\"discharging\":" + std::string(discharging ? "true" : "false") + ",";
    } else {
        json += "\"battery\":0,\"charging\":false,\"discharging\":false,";
    }

    // Add WiFi info
    if (!wifi.IsConfigMode()) {
        json += "\"ssid\":\"" + wifi.GetSsid() + "\",";
        json += "\"rssi\":" + std::to_string(wifi.GetRssi()) + ",";
        json += "\"channel\":" + std::to_string(wifi.GetChannel()) + ",";
        json += "\"ip\":\"" + wifi.GetIpAddress() + "\",";
    } else {
        json += "\"ssid\":\"\",\"rssi\":0,\"channel\":0,\"ip\":\"\",";
    }

    // Add chip temperature
    float temperature = 0.0f;
    if (board.GetTemperature(temperature)) {
        json += "\"temperature\":" + std::to_string(temperature) + ",";
    } else {
        json += "\"temperature\":0.0,";
    }

    // Remove trailing comma and close JSON
    if (json.back() == ',') {
        json.pop_back();
    }
    json += "}";

    return json;
}

