void Display::SetTheme(Theme *theme)
{
    if (theme == nullptr) {
        ESP_LOGW(TAG, "Cannot set null theme");
        return;
    }

    // Update the internal theme reference
    current_theme_ = theme;

    // Persist the theme name to settings storage
    Settings settings("display", true);  // Using "display" namespace with read/write access
    settings.SetString("theme_name", theme->name());
    settings.EraseAll();  // This might not be needed, but ensures settings are properly saved

    ESP_LOGI(TAG, "Theme set to: %s", theme->name().c_str());
}

