SingleLed::SingleLed(gpio_num_t gpio)
{
    // Configure LED strip settings
    led_strip_config_t strip_config = {
        .strip_gpio_num = gpio,
        .max_leds = 1,  // Single LED
        .led_model = LED_MODEL_WS2812,
        .flags = {
            .invert_out = false
        }
    };

    // Configure RMT settings for precise timing
    led_strip_rmt_config_t rmt_config = {
        .clk_src = RMT_CLK_SRC_DEFAULT,
        .resolution_hz = 10 * 1000 * 1000,  // 10MHz resolution
        .flags = {
            .with_dma = false
        }
    };

    // Create the LED strip
    ESP_ERROR_CHECK(led_strip_new_rmt_device(&strip_config, &rmt_config, &led_strip_));

    // Clear the LED initially (turn it off)
    led_strip_clear(led_strip_);

    // Create and configure the blink timer
    const esp_timer_create_args_t blink_timer_args = {
        .callback = [](void* arg) {
            SingleLed* led = static_cast<SingleLed*>(arg);
            led->OnBlinkTimer();
        },
        .arg = this,
        .name = "blink_timer"
    };

    ESP_ERROR_CHECK(esp_timer_create(&blink_timer_args, &blink_timer_));
}

