void SingleLed::StartBlinkTask(int times, int interval_ms)
{
    if (led_strip_ == nullptr)
    {
        return;
    }

    std::lock_guard<std::mutex> lock(mutex_);

    // Set up the blink counter
    // For infinite blinking, we use a large number
    if (times == BLINK_INFINITE)
    {
        blink_counter_ = INT_MAX;
    }
    else
    {
        blink_counter_ = times * 2; // Each blink consists of ON and OFF states
    }

    // Store the interval
    blink_interval_ms_ = interval_ms;

    // Start the timer
    esp_timer_start_periodic(blink_timer_, interval_ms * 1000); // Convert ms to microseconds
}

