void SingleLed::OnStateChanged()
{
    DeviceState state = Application::GetInstance().GetDeviceState();

    switch (state)
    {
        case kDeviceStateUnknown:
            TurnOff();
            break;

        case kDeviceStateStarting:
            SetColor(0, 0, 255); // Blue
            StartContinuousBlink(500); // Slow blink (500ms)
            break;

        case kDeviceStateWifiConfiguring:
            SetColor(255, 255, 0); // Yellow
            StartContinuousBlink(250); // Fast blink (250ms)
            break;

        case kDeviceStateIdle:
            SetColor(0, 255, 0); // Green
            TurnOn();
            break;

        case kDeviceStateConnecting:
            SetColor(0, 0, 255); // Blue
            StartContinuousBlink(300); // Medium blink (300ms)
            break;

        case kDeviceStateListening:
            SetColor(0, 255, 255); // Cyan
            StartContinuousBlink(100); // Fast blink (100ms)
            break;

        case kDeviceStateSpeaking:
            SetColor(255, 0, 0); // Red
            StartContinuousBlink(100); // Fast blink (100ms)
            break;

        case kDeviceStateUpgrading:
            SetColor(255, 0, 255); // Purple
            StartContinuousBlink(50); // Rapid blink (50ms)
            break;

        case kDeviceStateActivating:
            SetColor(255, 0, 255); // Magenta
            StartContinuousBlink(100); // Fast blink (100ms)
            break;

        case kDeviceStateAudioTesting:
            SetColor(255, 255, 255); // White
            StartContinuousBlink(100); // Fast blink (100ms)
            break;

        case kDeviceStateFatalError:
            SetColor(255, 0, 0); // Red
            StartContinuousBlink(50); // Rapid blink (50ms)
            break;

        default:
            TurnOff();
            break;
    }
}

