MqttProtocol::MqttProtocol()
{
    // Create event group for synchronization
    event_group_handle_ = xEventGroupCreate();
    if (event_group_handle_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create event group");
        return;
    }

    // Create reconnect timer
    esp_timer_create_args_t timer_args = {
        .callback = [](void* arg) {
            MqttProtocol* self = static_cast<MqttProtocol*>(arg);
            // Check if we're still alive before attempting reconnect
            if (*self->alive_) {
                // Schedule reconnect through application task scheduler
                Application::GetInstance().Schedule([self]() {
                    if (*self->alive_) {
                        self->StartMqttClient(false);
                    }
                });
            }
        },
        .name = "mqtt_reconnect",
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK
    };

    esp_err_t err = esp_timer_create(&timer_args, &reconnect_timer_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create reconnect timer: %s", esp_err_to_name(err));
        vEventGroupDelete(event_group_handle_);
        event_group_handle_ = nullptr;
        return;
    }
}

