MqttProtocol::~MqttProtocol()
{
    // Stop and delete the reconnect timer
    if (reconnect_timer_) {
        esp_timer_stop(reconnect_timer_);
        esp_timer_delete(reconnect_timer_);
    }

    // Reset UDP and MQTT resources
    udp_.reset();
    mqtt_.reset();

    // Release the event group
    if (event_group_handle_) {
        vEventGroupDelete(event_group_handle_);
    }

    // Mark the instance as inactive by setting alive flag to false
    if (alive_) {
        alive_->store(false);
    }
}

