bool MqttProtocol::StartMqttClient(bool report_error)
{
    // Check if we're already alive (not being destroyed)
    if (!*alive_) {
        ESP_LOGE(TAG, "MQTT client is not alive");
        return false;
    }

    // Get configuration settings
    auto &settings = Settings::GetInstance();

    // Create MQTT client instance
    mqtt_ = std::make_unique<Mqtt>();

    // Configure MQTT client
    MqttConfig config;
    config.broker_address = settings.GetMqttBrokerAddress();
    config.broker_port = settings.GetMqttBrokerPort();
    config.client_id = settings.GetDeviceId();
    config.username = settings.GetMqttUsername();
    config.password = settings.GetMqttPassword();
    config.keep_alive = MQTT_PING_INTERVAL_SECONDS;
    config.clean_session = true;

    // Set up connection callback
    mqtt_->OnConnected([this]() {
        ESP_LOGI(TAG, "MQTT connected successfully");
        // Reset reconnect timer on successful connection
        if (reconnect_timer_ != nullptr) {
            esp_timer_stop(reconnect_timer_);
        }

        // Subscribe to topics here if needed
        // Example: mqtt_->Subscribe("device/topic", 0);

        // Set publish topic
        publish_topic_ = "device/" + Settings::GetInstance().GetDeviceId() + "/status";
    });

    // Set up disconnect callback
    mqtt_->OnDisconnected([this]() {
        ESP_LOGW(TAG, "MQTT disconnected");
        if (*alive_) {
            // Schedule reconnection attempt
            esp_timer_start_once(reconnect_timer_, MQTT_RECONNECT_INTERVAL_MS * 1000);
        }
    });

    // Set up message received callback
    mqtt_->OnMessage([this](const std::string &topic, const std::string &payload) {
        ESP_LOGI(TAG, "MQTT message received on topic: %s", topic.c_str());

        // Parse JSON payload
        cJSON *root = cJSON_Parse(payload.c_str());
        if (root == nullptr) {
            ESP_LOGE(TAG, "Failed to parse JSON payload");
            return;
        }

        // Handle different message types
        auto type = cJSON_GetObjectItem(root, "type");
        if (type && cJSON_IsString(type)) {
            if (strcmp(type->valuestring, "hello") == 0) {
                ParseServerHello(root);
            } else if (strcmp(type->valuestring, "goodbye") == 0) {
                // Handle goodbye message - close audio channel
                CloseAudioChannel();
            }
        }

        cJSON_Delete(root);
    });

    // Initialize MQTT client with configuration
    if (!mqtt_->Init(config)) {
        ESP_LOGE(TAG, "Failed to initialize MQTT client");
        if (report_error) {
            SetError(Lang::Strings::CONNECTION_FAILED);
        }
        return false;
    }

    // Connect to broker
    if (!mqtt_->Connect()) {
        ESP_LOGE(TAG, "Failed to connect to MQTT broker");
        if (report_error) {
            SetError(Lang::Strings::CONNECTION_FAILED);
        }
        return false;
    }

    return true;
}

