bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (packet == nullptr) {
        ESP_LOGE(TAG, "Invalid audio packet");
        return false;
    }

    // Check if UDP channel is open
    if (udp_ == nullptr) {
        ESP_LOGE(TAG, "UDP channel is not open");
        return false;
    }

    // Prepare the packet data with proper format
    // UDP Encrypted OPUS Packet Format:
    // |type 1u|flags 1u|payload_len 2u|ssrc 4u|timestamp 4u|sequence 4u|payload payload_len|

    // Create nonce with packet size, timestamp, and sequence number
    uint8_t nonce[16];
    memcpy(nonce, aes_nonce_.data(), aes_nonce_.size());

    // Update nonce with packet information (assuming we use the last 4 bytes for sequence number)
    // This follows the pattern seen in the receive side where nonce is extracted from packet data
    uint32_t sequence = local_sequence_++;
    uint32_t timestamp = packet->timestamp;
    uint16_t payload_len = packet->payload.size();

    // Fill in the nonce fields (assuming the nonce format is [nonce_base][sequence][timestamp])
    // For simplicity, we'll use a fixed approach similar to what's done in the receive path
    *(uint32_t*)(nonce + aes_nonce_.size() - 8) = htonl(sequence);
    *(uint32_t*)(nonce + aes_nonce_.size() - 4) = htonl(timestamp);

    // Build the complete packet with header
    std::string packet_data;
    packet_data.reserve(16 + packet->payload.size()); // minimum header + payload

    // Add packet header fields
    packet_data.push_back(0x01); // type
    packet_data.push_back(0x00); // flags
    packet_data.append(reinterpret_cast<char*>(&payload_len), 2); // payload length (network byte order)
    uint32_t ssrc = 0; // ssrc field (set to 0 for now)
    packet_data.append(reinterpret_cast<char*>(&ssrc), 4); // ssrc
    packet_data.append(reinterpret_cast<char*>(&timestamp), 4); // timestamp
    packet_data.append(reinterpret_cast<char*>(&sequence), 4); // sequence

    // Add the actual payload
    packet_data.append(packet->payload);

    // Encrypt the payload part of the packet
    size_t encrypted_size = packet_data.size() - aes_nonce_.size();
    if (encrypted_size > 0) {
        // Prepare encryption context
        size_t nc_off = 0;
        uint8_t stream_block[16] = {0};

        // Extract the payload portion to encrypt
        auto payload_start = aes_nonce_.size();
        auto encrypted_payload = packet_data.data() + payload_start;

        // Encrypt the payload in-place
        int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, 
                                       encrypted_size, 
                                       &nc_off, 
                                       nonce, 
                                       stream_block, 
                                       reinterpret_cast<const uint8_t*>(encrypted_payload),
                                       reinterpret_cast<uint8_t*>(packet_data.data() + payload_start));

        if (ret != 0) {
            ESP_LOGE(TAG, "Failed to encrypt audio data, ret: %d", ret);
            return false;
        }
    }

    // Send over UDP in a thread-safe manner
    {
        std::lock_guard<std::mutex> lock(channel_mutex_);
        if (!udp_ || !udp_->IsConnected()) {
            ESP_LOGE(TAG, "UDP socket is not connected");
            return false;
        }

        // Send the encrypted packet
        if (!udp_->Send(packet_data)) {
            ESP_LOGE(TAG, "Failed to send audio packet over UDP");
            return false;
        }
    }

    return true;
}

