bool MqttProtocol::OpenAudioChannel()
{
    ESP_LOGI(TAG, "Opening audio channel");

    // Check if MQTT is connected
    if (mqtt_ == nullptr) {
        ESP_LOGE(TAG, "MQTT client not initialized");
        return false;
    }

    // Send hello message to request audio channel
    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message)) {
        ESP_LOGE(TAG, "Failed to send hello message");
        return false;
    }

    // Wait for server hello response with timeout
    TickType_t timeout_ticks = pdMS_TO_TICKS(5000); // 5 second timeout
    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_,
        MQTT_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,   // Clear bits on exit
        pdFALSE,  // Wait for any bit
        timeout_ticks
    );

    if (!(bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT)) {
        ESP_LOGE(TAG, "Timeout waiting for server hello response");
        SetError(Lang::Strings::SERVER_TIMEOUT);
        return false;
    }

    // Create UDP socket for audio data
    auto network = Board::GetInstance().GetNetwork();
    udp_ = network->CreateUdp();

    if (udp_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create UDP socket");
        return false;
    }

    // Connect to UDP server
    if (!udp_->Connect(udp_server_, udp_port_)) {
        ESP_LOGE(TAG, "Failed to connect to UDP server %s:%d", udp_server_.c_str(), udp_port_);
        udp_.reset();
        return false;
    }

    // Set up audio channel closed callback
    udp_->OnData([this](const std::string& data) {
        // Process incoming audio data
        if (data.size() < 16) { // Minimum header size
            ESP_LOGW(TAG, "Invalid audio packet size: %zu", data.size());
            return;
        }

        // Extract sequence number from nonce (last 4 bytes)
        uint32_t remote_seq = ntohl(*((uint32_t*)(data.data() + 12)));

        // Check sequence number
        if (remote_seq <= remote_sequence_) {
            ESP_LOGW(TAG, "Dropping duplicate or out-of-order packet: %u (current: %u)", 
                    remote_seq, remote_sequence_);
            return;
        }

        // Update remote sequence number
        remote_sequence_ = remote_seq;

        // Decrypt audio data
        std::string decrypted;
        decrypted.resize(data.size() - 16); // Remove nonce header

        size_t nc_off = 0;
        uint8_t stream_block[16] = {0};
        std::string nonce = data.substr(0, 16);

        if (mbedtls_aes_crypt_ctr(&aes_ctx_, decrypted.size(), &nc_off, 
                                  (uint8_t*)nonce.c_str(), stream_block,
                                  (uint8_t*)data.data() + 16, 
                                  (uint8_t*)decrypted.data()) != 0) {
            ESP_LOGE(TAG, "Failed to decrypt audio data");
            return;
        }

        // Create audio packet and pass to callback
        auto packet = std::make_unique<AudioStreamPacket>();
        packet->payload = std::move(decrypted);
        packet->timestamp = 0; // Server should provide timestamp in real implementation

        if (on_audio_packet_ != nullptr) {
            on_audio_packet_(std::move(packet));
        }
    });

    ESP_LOGI(TAG, "Audio channel opened successfully");
    return true;
}

