void MqttProtocol::ParseServerHello(const cJSON *root)
{
    // Extract session ID
    auto session_id = cJSON_GetObjectItem(root, "session_id");
    if (cJSON_IsString(session_id)) {
        session_id_ = session_id->valuestring;
        ESP_LOGI(TAG, "Session ID: %s", session_id_.c_str());
    }

    // Extract transport information
    auto transport = cJSON_GetObjectItem(root, "transport");
    if (transport == nullptr || strcmp(transport->valuestring, "udp") != 0) {
        ESP_LOGE(TAG, "Unsupported transport: %s", transport ? transport->valuestring : "null");
        return;
    }

    // Extract server address and port
    auto server = cJSON_GetObjectItem(root, "server");
    if (server != nullptr) {
        auto address = cJSON_GetObjectItem(server, "address");
        auto port = cJSON_GetObjectItem(server, "port");
        if (cJSON_IsString(address) && cJSON_IsNumber(port)) {
            udp_server_ = address->valuestring;
            udp_port_ = port->valueint;
            ESP_LOGI(TAG, "UDP Server: %s:%d", udp_server_.c_str(), udp_port_);
        }
    }

    // Extract encryption key and nonce
    auto encryption = cJSON_GetObjectItem(root, "encryption");
    if (encryption != nullptr) {
        auto key = cJSON_GetObjectItem(encryption, "key");
        auto nonce = cJSON_GetObjectItem(encryption, "nonce");

        if (cJSON_IsString(key) && cJSON_IsString(nonce)) {
            // Decode the hex key
            std::string decoded_key = DecodeHexString(key->valuestring);
            if (decoded_key.size() == 16) { // AES-128 requires 16 byte key
                // Initialize AES context
                mbedtls_aes_init(&aes_ctx_);
                if (mbedtls_aes_setkey_enc(&aes_ctx_, (const unsigned char*)decoded_key.data(), 128) != 0) {
                    ESP_LOGE(TAG, "Failed to set AES key");
                    return;
                }

                // Store nonce
                aes_nonce_ = DecodeHexString(nonce->valuestring);
                if (aes_nonce_.size() != 16) {
                    ESP_LOGW(TAG, "Invalid nonce length: %zu", aes_nonce_.size());
                }

                ESP_LOGI(TAG, "AES encryption initialized with key and nonce");
            } else {
                ESP_LOGE(TAG, "Invalid key length: %zu", decoded_key.size());
            }
        }
    }

    // Extract audio parameters
    auto audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (cJSON_IsObject(audio_params)) {
        auto sample_rate = cJSON_GetObjectItem(audio_params, "sample_rate");
        auto frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");

        if (cJSON_IsNumber(sample_rate)) {
            server_sample_rate_ = sample_rate->valueint;
        }

        if (cJSON_IsNumber(frame_duration)) {
            server_frame_duration_ = frame_duration->valueint;
        }
    }

    // Signal that server hello has been processed
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
}

static inline uint8_t CharToHex(char c)
{
    if (c >= '0' && c <= '9') {
        return c - '0';
    }
    if (c >= 'A' && c <= 'F') {
        return c - 'A' + 10;
    }
    if (c >= 'a' && c <= 'f') {
        return c - 'a' + 10;
    }
    return 0;
}

std::string MqttProtocol::DecodeHexString(const std::string &hex_string)
{
    std::string result;
    result.reserve(hex_string.length() / 2);

    for (size_t i = 0; i < hex_string.length(); i += 2)
    {
        // Check if we have at least 2 characters left
        if (i + 1 < hex_string.length())
        {
            uint8_t high_nibble = CharToHex(hex_string[i]);
            uint8_t low_nibble = CharToHex(hex_string[i + 1]);
            uint8_t byte_value = (high_nibble << 4) | low_nibble;
            result.push_back(static_cast<char>(byte_value));
        }
        // If odd number of characters, ignore the last one (or handle as needed)
        // Based on typical hex decoding behavior, we'll skip incomplete pairs
    }

    return result;
}

