bool Protocol::IsTimeout() const
{
    auto now = std::chrono::steady_clock::now();
    auto elapsed = std::chrono::duration_cast<std::chrono::seconds>(now - last_incoming_time_);

    if (elapsed.count() > 120) {
        ESP_LOGE(TAG, "Channel timeout detected");
        return true;
    }

    return false;
}

