bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        return false;
    }

    // Prepare the audio data for sending
    const auto& audio_packet = *packet;

    // Get current timestamp
    auto now = std::chrono::duration_cast<std::chrono::milliseconds>(
        std::chrono::steady_clock::now().time_since_epoch()).count();

    // Format based on protocol version
    std::vector<uint8_t> buffer;

    if (version_ == 2)
    {
        // Binary Protocol v2 format
        struct BinaryProtocol2 bp2;
        bp2.version = htons(2);
        bp2.type = htons(1); // Assuming type 1 for audio data
        bp2.timestamp = htonl(static_cast<uint32_t>(audio_packet.timestamp));
        bp2.payload_size = htonl(static_cast<uint32_t>(audio_packet.payload.size()));

        // Copy header
        buffer.resize(sizeof(BinaryProtocol2) + audio_packet.payload.size());
        memcpy(buffer.data(), &bp2, sizeof(BinaryProtocol2));
        memcpy(buffer.data() + sizeof(BinaryProtocol2), audio_packet.payload.data(), audio_packet.payload.size());
    }
    else if (version_ == 3)
    {
        // Binary Protocol v3 format
        struct BinaryProtocol3 bp3;
        bp3.type = 1; // Assuming type 1 for audio data
        bp3.payload_size = htons(static_cast<uint16_t>(audio_packet.payload.size()));

        // Copy header
        buffer.resize(sizeof(BinaryProtocol3) + audio_packet.payload.size());
        memcpy(buffer.data(), &bp3, sizeof(BinaryProtocol3));
        memcpy(buffer.data() + sizeof(BinaryProtocol3), audio_packet.payload.data(), audio_packet.payload.size());
    }
    else
    {
        // Raw payload format
        buffer = audio_packet.payload;
    }

    // Send the formatted data
    if (!websocket_->Send(reinterpret_cast<const char*>(buffer.data()), buffer.size(), true))
    {
        ESP_LOGE(TAG, "Failed to send audio data");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    return true;
}

bool WebsocketProtocol::SendText(const std::string &text)
{
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        return false;
    }

    if (!websocket_->Send(text.data(), text.size(), false))
    {
        ESP_LOGE(TAG, "Failed to send text message");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    return true;
}

