bool WebsocketProtocol::OpenAudioChannel()
{
    // Create WebSocket instance
    websocket_ = std::make_unique<WebSocket>();

    // Configure WebSocket connection parameters
    // Set authentication headers if needed
    std::map<std::string, std::string> headers;

    // Add authentication token if available
    if (!session_id_.empty()) {
        headers["Authorization"] = "Bearer " + session_id_;
    }

    // Add device identification headers
    headers["Device-ID"] = Board::GetDeviceId();
    headers["Device-Type"] = "ESP32";

    // Set protocol version
    headers["Protocol-Version"] = std::to_string(version_);

    // Connect to WebSocket server
    // Note: This assumes WebSocket has a Connect method that takes URL, headers, etc.
    // Since exact API isn't visible, I'll use a generic approach
    std::string url = Settings::GetWebsocketUrl();

    if (!websocket_->Connect(url, headers)) {
        ESP_LOGE(TAG, "Failed to connect to WebSocket server");
        websocket_.reset();
        return false;
    }

    // Set up data handler for binary audio packets
    websocket_->SetDataHandler([this](const uint8_t* data, size_t length, bool is_binary) {
        if (!is_binary) {
            return;
        }

        // Handle different protocol versions
        if (version_ == 2) {
            if (length < sizeof(BinaryProtocol2)) {
                ESP_LOGW(TAG, "Invalid packet size for protocol v2");
                return;
            }

            const BinaryProtocol2* bp2 = reinterpret_cast<const BinaryProtocol2*>(data);

            // Convert bytes from network order to host order
            uint16_t version = ntohs(bp2->version);
            uint32_t timestamp = ntohl(bp2->timestamp);
            uint32_t payload_size = ntohl(bp2->payload_size);

            // Validate packet
            if (payload_size > length - sizeof(BinaryProtocol2)) {
                ESP_LOGW(TAG, "Payload size exceeds packet size");
                return;
            }

            // Process audio packet
            AudioStreamPacket packet;
            packet.timestamp = timestamp;
            packet.payload.assign(bp2->payload, bp2->payload + payload_size);

            // Handle the packet (this would typically call a callback or queue)
            // For now, we'll just log it
            ESP_LOGD(TAG, "Received v2 audio packet, size: %zu", payload_size);
        }
        else if (version_ == 3) {
            if (length < sizeof(BinaryProtocol3)) {
                ESP_LOGW(TAG, "Invalid packet size for protocol v3");
                return;
            }

            const BinaryProtocol3* bp3 = reinterpret_cast<const BinaryProtocol3*>(data);

            // Convert bytes from network order to host order
            uint16_t payload_size = ntohs(bp3->payload_size);

            // Validate packet
            if (payload_size > length - sizeof(BinaryProtocol3)) {
                ESP_LOGW(TAG, "Payload size exceeds packet size");
                return;
            }

            // Process audio packet
            AudioStreamPacket packet;
            packet.payload.assign(bp3->payload, bp3->payload + payload_size);

            // Handle the packet (this would typically call a callback or queue)
            // For now, we'll just log it
            ESP_LOGD(TAG, "Received v3 audio packet, size: %zu", payload_size);
        }
        else {
            // Handle raw packet for other versions
            AudioStreamPacket packet;
            packet.payload.assign(data, data + length);

            // Handle the packet
            ESP_LOGD(TAG, "Received raw audio packet, size: %zu", length);
        }
    });

    // Send hello message to establish connection
    std::string hello_message = GetHelloMessage();
    if (!websocket_->Send(hello_message)) {
        ESP_LOGE(TAG, "Failed to send hello message");
        websocket_.reset();
        return false;
    }

    // Wait for server hello response (timeout mechanism would be implemented here)
    // For now, we assume success after sending hello
    ESP_LOGI(TAG, "Audio channel opened successfully");
    return true;
}

