std::string WebsocketProtocol::GetHelloMessage()
{
    cJSON *root = cJSON_CreateObject();

    // Set message type
    cJSON_AddStringToObject(root, "type", "hello");

    // Set protocol version
    cJSON_AddNumberToObject(root, "version", version_);

    // Set supported features
    cJSON *features = cJSON_CreateObject();
    cJSON_AddBoolToObject(features, "aec", true);
    cJSON_AddBoolToObject(features, "mcp", true);
    cJSON_AddItemToObject(root, "features", features);

    // Set transport method
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Set audio parameters
    cJSON *audio_params = cJSON_CreateObject();

    // Get audio configuration from board
    #ifdef AUDIO_INPUT_SAMPLE_RATE
    cJSON_AddNumberToObject(audio_params, "sample_rate", AUDIO_INPUT_SAMPLE_RATE);
    #else
    cJSON_AddNumberToObject(audio_params, "sample_rate", 24000);
    #endif

    // Set audio format (assuming opus format based on typical usage)
    cJSON_AddStringToObject(audio_params, "format", "opus");

    // Set channels (typically 1 for microphone input)
    cJSON_AddNumberToObject(audio_params, "channels", 1);

    // Set frame duration (typical value)
    cJSON_AddNumberToObject(audio_params, "frame_duration", 60);

    cJSON_AddItemToObject(root, "audio_params", audio_params);

    // Set device info
    cJSON *device = cJSON_CreateObject();
    cJSON_AddStringToObject(device, "id", SystemInfo::GetMacAddress().c_str());
    cJSON_AddStringToObject(device, "client_id", Board::GetInstance().GetUuid().c_str());
    cJSON_AddItemToObject(root, "device", device);

    // Convert to string
    char *json_string = cJSON_Print(root);
    std::string result = json_string;

    // Clean up
    cJSON_Delete(root);
    free(json_string);

    return result;
}

